/* ─────────────────────────────────────────────────────────
   QuantyFin Design System — Color & Type Tokens
   Canonical reference: DESIGN.md (this project)
   ─────────────────────────────────────────────────────────
   Architecture (v3):
     · Foundation tokens (brand, accent, status, font families,
       motion, a11y) live in :root — universal across surfaces.
     · Surface scale (type-size, gutter, container-max,
       motion-budget, accent-freq) resolves through one of:
         [data-surface="portal"]     ← default if omitted
         [data-surface="marketing"]
         [data-surface="app"]
         [data-surface="store"]      ← scoped for v3.1
     · Set the attribute on <body> or any container.

   Color discipline:
     · Iris  → AI/tech default · 90% of accent surface
     · Gold  → climax · 1 moment / page max · achievement
     · Mint  → growth · LIVE · prosperity
     · Rose  → human · warm · ESG / people
     · Brand → primary anchor · headlines · navy ink
     · Crimson (--gap) → ALERT ONLY · not for governance

   Type discipline (4 families — canonical, no others):
     · Be Vietnam Pro → body default · brand chrome · VN-first (self-hosted)
     · Montserrat     → impact display · headlines · numerals
     · Playfair Italic → Hero ONLY (1 art moment / portal)
     · JetBrains Mono → tags · code · technical metadata
     · Motion tokens (semantic --motion-* aliases) are aliased
       below so legacy preview files keep working.
   ───────────────────────────────────────────────────────── */

@import url('https://fonts.googleapis.com/css2?family=Montserrat:wght@400;500;600;700;800;900&family=Playfair+Display:ital,wght@1,400;1,500;1,600;1,700;1,800;1,900&family=JetBrains+Mono:wght@400;500;600;700&display=swap');

/* ── Be Vietnam Pro — brand font (self-hosted, full weight range) ── */
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 100; font-style: normal; font-display: swap; src: url('fonts/BeVietnamPro-Thin.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 100; font-style: italic; font-display: swap; src: url('fonts/BeVietnamPro-ThinItalic.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 200; font-style: normal; font-display: swap; src: url('fonts/BeVietnamPro-ExtraLight.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 200; font-style: italic; font-display: swap; src: url('fonts/BeVietnamPro-ExtraLightItalic.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 300; font-style: normal; font-display: swap; src: url('fonts/BeVietnamPro-Light.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 300; font-style: italic; font-display: swap; src: url('fonts/BeVietnamPro-LightItalic.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 400; font-style: normal; font-display: swap; src: url('fonts/BeVietnamPro-Regular.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 400; font-style: italic; font-display: swap; src: url('fonts/BeVietnamPro-Italic.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 500; font-style: normal; font-display: swap; src: url('fonts/BeVietnamPro-Medium.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 500; font-style: italic; font-display: swap; src: url('fonts/BeVietnamPro-MediumItalic.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 600; font-style: normal; font-display: swap; src: url('fonts/BeVietnamPro-SemiBold.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 600; font-style: italic; font-display: swap; src: url('fonts/BeVietnamPro-SemiBoldItalic.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 700; font-style: normal; font-display: swap; src: url('fonts/BeVietnamPro-Bold.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 700; font-style: italic; font-display: swap; src: url('fonts/BeVietnamPro-BoldItalic.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 800; font-style: normal; font-display: swap; src: url('fonts/BeVietnamPro-ExtraBold.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 800; font-style: italic; font-display: swap; src: url('fonts/BeVietnamPro-ExtraBoldItalic.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 900; font-style: normal; font-display: swap; src: url('fonts/BeVietnamPro-Black.ttf') format('truetype'); }
@font-face { font-family: 'Be Vietnam Pro'; font-weight: 900; font-style: italic; font-display: swap; src: url('fonts/BeVietnamPro-BlackItalic.ttf') format('truetype'); }

:root {
  /* ═══ BRAND (anchor) ═══ */
  --brand:        #2a2b86;   /* QuantyFin Navy — primary */
  --brand-light:  #4a4bc8;   /* gradient pair */
  --brand-deep:   #16175a;   /* deep variant for big-num gradient */
  --brand-tint:   #eeeefb;
  --brand-gold:   #fcaf16;   /* alias */

  /* ═══ ACCENTS · semantic ═══ */
  --iris:        #7c6cf5;   /* AI/tech · default accent */
  --iris-deep:   #4a4bc8;
  --iris-tint:   #eeeefb;

  --gold:        #fcaf16;   /* climax · 1/page */
  --gold-deep:   #b07a00;
  --gold-tint:   #fff4d8;

  --mint:        #10b981;   /* growth · live */
  --mint-deep:   #047857;
  --mint-tint:   #d1fae5;

  --rose:        #f472b6;   /* human · warm */
  --rose-deep:   #be185d;
  --rose-tint:   #fde7f1;

  /* Legacy aliases — keep compatibility with older previews */
  --accent:       var(--iris);
  --accent-tint:  var(--iris-tint);

  /* ═══ STATUS ═══ */
  --live:    var(--mint);     --live-bg:  rgba(16,185,129,.10);
  --build:   var(--iris);     --build-bg: rgba(124,108,245,.10);
  --gap:     #ef4444;         --gap-bg:   rgba(239,68,68,.08);     /* ALERT only */
  --plan:    #f59e0b;         --plan-bg:  rgba(245,158,11,.10);
  --plan-deep: #7a5400;

  /* ═══ TEXT ═══ */
  --fg-1: #1a1b3a;   /* primary ink — navy-tinted, NOT pure black */
  --fg-2: #5a5c7e;   /* secondary — body, descriptions */
  --fg-3: #6b6d8c;   /* tertiary — labels, metadata (lifted from 9a9cb8 for projector legibility) */
  --fg-brand: var(--brand);
  --fg-on-brand: #ffffff;

  /* Legacy aliases */
  --text-1: var(--fg-1);
  --text-2: var(--fg-2);
  --text-3: var(--fg-3);

  /* ═══ SURFACES ═══ */
  --bg:        #fcfcff;   /* Paper */
  --bg-2:      #f4f5fb;   /* Mist — section alt bands */
  --bg-muted:  #ecedf8;   /* Lavender — chip / hover */
  --bg-ink:    #0e0f24;   /* Dark surface — hero / footer */
  --bg-warm:   #fbfaf6;   /* Hero warm wash */

  --border:        #e6e7f2;
  --border-light:  #f0f1f8;
  --border-hover:  #d0d2e8;

  /* ═══ SHADOWS (iris-tinted, weightless) ═══ */
  --shadow-sm: 0 1px 2px  rgba(74,75,200,0.05);
  --shadow:    0 2px 6px  rgba(74,75,200,0.06);
  --shadow-md: 0 4px 16px rgba(74,75,200,0.08);
  --shadow-lg: 0 12px 32px rgba(74,75,200,0.12);
  --shadow-xl: 0 16px 40px rgba(74,75,200,0.14);
  --shadow-gold: 0 12px 32px rgba(252,175,22,0.32);
  --shadow-brand: 0 12px 32px rgba(42,43,134,0.32);

  /* ═══ RADIUS ═══ */
  --radius-xs:   4px;
  --radius-sm:   8px;
  --radius:      12px;
  --radius-md:   14px;
  --radius-lg:   16px;
  --radius-xl:   24px;
  --radius-pill: 9999px;

  /* ═══ SPACING (4px base) ═══ */
  --s-1: 4px;  --s-2: 8px;  --s-3: 12px; --s-4: 16px;
  --s-5: 20px; --s-6: 24px; --s-8: 32px; --s-10: 40px;
  --s-12: 48px; --s-14: 56px; --s-16: 64px; --s-18: 72px;
  --s-20: 80px; --s-24: 96px; --s-28: 112px;

  /* ═══ TYPOGRAPHY ═══ */
  --font-body:    'Be Vietnam Pro', 'Helvetica Neue', Arial, sans-serif;
  --font-ui:      'Be Vietnam Pro', 'Helvetica Neue', Arial, sans-serif;  /* alias */
  --font-sans:    'Be Vietnam Pro', 'Helvetica Neue', Arial, sans-serif;  /* alias */
  --font-brand:   'Be Vietnam Pro', 'Helvetica Neue', Arial, sans-serif;
  --font-impact:  'Montserrat', 'Be Vietnam Pro', sans-serif;        /* impact display */
  --font-display: 'Montserrat', 'Be Vietnam Pro', sans-serif;        /* alias */
  --font-serif:   'Playfair Display', Georgia, serif;                /* Hero ONLY */
  --font-numeric: 'Montserrat', 'Be Vietnam Pro', sans-serif;        /* tabular */
  --font-mono:    'JetBrains Mono', 'SFMono-Regular', Menlo, monospace;

  /* Type scale — blog-portal sizing · generous, lean-back readable */
  --type-hero:        800 clamp(80px, 8.4vw, 120px)/0.94 var(--font-impact);
  --type-display:     800 clamp(64px, 6.4vw, 96px)/0.98 var(--font-impact);
  --type-h1:          800 clamp(48px, 5.2vw, 64px)/1.08 var(--font-impact);
  --type-h2:          700 clamp(32px, 3.4vw, 40px)/1.18 var(--font-impact);
  --type-h3:          700 26px/1.3 var(--font-impact);
  --type-card-title:  700 20px/1.35 var(--font-brand);
  --type-kpi:         800 clamp(48px, 4.6vw, 64px)/0.9 var(--font-numeric);

  /* Numeral rhythm — Montserrat italic 800 (NOT Playfair) — geometric not ornamental */
  --type-roman:       italic 800 clamp(64px, 6.4vw, 96px)/0.85 var(--font-impact);

  /* Hero artistic accent — Playfair italic — RESERVE FOR HERO ONLY */
  --type-art-italic:  italic 800 clamp(80px, 8.4vw, 120px)/0.94 var(--font-serif);

  --type-body-lg:     400 23px/1.65 var(--font-body);   /* section lede */
  --type-body:        400 19px/1.7  var(--font-body);   /* default body — blog readable */
  --type-body-sm:     400 16px/1.6  var(--font-body);
  --type-label:       500 14px/1.4  var(--font-body);
  --type-caption:     400 13px/1.5  var(--font-body);

  --type-mono:        500 13px/1.5  var(--font-mono);
  --type-tag:         700 12px/1    var(--font-mono);
  --type-eyebrow:     700 13px/1    var(--font-mono);  /* 0.32em tracking — set inline */

  /* ═══ MOTION ═══ */
  --ease-out:        cubic-bezier(0.4, 0, 0.2, 1);
  --ease-overshoot:  cubic-bezier(0.34, 1.56, 0.64, 1);
  --dur-fast: 150ms; --dur: 200ms; --dur-slow: 300ms;

  /* ═══ A11Y FLOOR (v3 · universal) ═══ */
  --focus-ring:        0 0 0 3px rgba(124,108,245,0.40);
  --focus-ring-gold:   0 0 0 3px rgba(252,175,22,0.45);
  --focus-ring-gap:    0 0 0 3px rgba(239,68,68,0.40);
  --tap-min:           44px;     /* override per-surface: 56px store, 72px primary CTA */

  /* MOTION semantic aliases (compat for legacy previews using motion.css names) */
  --motion-enter:   250ms cubic-bezier(0.34, 1.56, 0.64, 1);
  --motion-exit:    180ms cubic-bezier(0.4, 0, 0.2, 1);
  --motion-hover:   150ms cubic-bezier(0.4, 0, 0.2, 1);
  --motion-press:   80ms  ease-out;
  --motion-page:    300ms cubic-bezier(0.4, 0, 0.2, 1);
  --motion-count:   600ms cubic-bezier(0.2, 0.6, 0.2, 1);

  /* ═══ SURFACE DEFAULTS — portal scale (v3 adapter contract) ═══ */
  /* These are PORTAL defaults so existing previews keep working without `data-surface`.
     The marketing / app / store adapter blocks below override only what differs. */
  --gutter:        20px;
  --gutter-tight:  12px;
  --gutter-wide:   32px;
  --section-pad:   clamp(48px, 8vw, 96px) clamp(24px, 4vw, 56px);
  --container-max: 1280px;
  --motion-budget: ambient;       /* 1 ambient/page · respect reduce-motion */
  --accent-freq:   narrative;     /* 1 gold climax · ≤2 accent / section */
  --shadow-rest:   var(--shadow-sm);

  /* Button scale (portal default) — see foundation/buttons.css */
  --btn-h-sm:   40px;  --btn-px-sm: 18px; --btn-fs-sm: 15px;
  --btn-h:      52px;  --btn-px:    28px; --btn-fs:    17px;
  --btn-h-lg:   64px;  --btn-px-lg: 36px; --btn-fs-lg: 19px;
  --btn-radius: var(--radius-pill);

  /* Form scale (portal default) — see foundation/forms.css */
  --input-h-sm:    36px;
  --input-h:       44px;
  --input-h-lg:    52px;
  --input-fs:      16px;
  --input-px:      14px;
  --input-radius:  10px;
  --check-size:    18px;
  --radio-size:    18px;
  --toggle-w:      40px;
  --toggle-h:      22px;
  --toggle-pad:    3px;

  /* Admin-grade type roles (portal defaults; app overrides for density) */
  --type-h4:        600 18px/1.3   var(--font-brand);
  --type-label-sm:  600 11px/1     var(--font-body);
  --type-num-lg:    700 36px/1.05  var(--font-numeric);
  --type-num:       600 22px/1.1   var(--font-numeric);
  --type-num-sm:    600 15px/1.2   var(--font-numeric);

  /* ═══ BIG NUMERAL GRADIENT (per-tone, for hero KPIs) ═══ */
  --grad-brand: linear-gradient(180deg, #2a2b86 0%, #16175a 100%);
  --grad-iris:  linear-gradient(180deg, #7c6cf5 0%, #4a4bc8 100%);
  --grad-gold:  linear-gradient(180deg, #fcaf16 0%, #b07a00 100%);
  --grad-mint:  linear-gradient(180deg, #10b981 0%, #047857 100%);
  --grad-rose:  linear-gradient(180deg, #f472b6 0%, #be185d 100%);
}

/* ══════════════════════════════════════════════════════
   SURFACE ADAPTERS — v3 multi-surface architecture
   ---------------------------------------------------
   Foundation tokens above are universal.
   Each adapter resolves SCALE for its archetype:
     · portal     — default (uses :root above; executive briefing / report)
     · marketing  — landing pages, public web
     · app        — internal admin (back-office, dashboards, internal mobile)
     · store      — POS / signage / fitting-room tablet (build out at v3.1)
   Activate by setting `data-surface="..."` on <body> or any container.
   ═════════════════════════════════════════════════════ */

/* ─── PORTAL — default (already in :root, declared here for clarity) ─── */
[data-surface="portal"] {
  --motion-budget: ambient;
  --accent-freq:   narrative;
  --container-max: 1280px;
  --section-pad:   clamp(48px, 8vw, 96px) clamp(24px, 4vw, 56px);

  /* Button scale */
  --btn-h-sm:  40px;  --btn-px-sm: 18px; --btn-fs-sm: 15px;
  --btn-h:     52px;  --btn-px:    28px; --btn-fs:    17px;
  --btn-h-lg:  64px;  --btn-px-lg: 36px; --btn-fs-lg: 19px;
  --btn-radius: var(--radius-pill);
}

/* ─── MARKETING — landing pages, public web ─── */
[data-surface="marketing"] {
  /* Type — hero scales up, body slightly lighter LH */
  --type-hero:     800 clamp(72px, 8vw,   120px)/0.94 var(--font-impact);
  --type-display:  800 clamp(56px, 5.6vw, 88px)/0.98  var(--font-impact);
  --type-h1:       800 clamp(40px, 4.4vw, 56px)/1.08  var(--font-impact);
  --type-h2:       700 clamp(28px, 3vw,   36px)/1.18  var(--font-impact);
  --type-body-lg:  400 22px/1.55 var(--font-body);
  --type-body:     400 19px/1.6  var(--font-body);
  --type-body-sm:  400 16px/1.55 var(--font-body);

  /* Layout */
  --gutter:        24px;
  --gutter-wide:   40px;
  --section-pad:   clamp(72px, 10vw, 160px) clamp(24px, 6vw, 80px);
  --container-max: 1200px;

  /* Discipline */
  --motion-budget: rich;            /* scroll-reveal · parallax OK */
  --accent-freq:   bold;            /* full-bleed brand sections OK */
  --shadow-rest:   var(--shadow);

  /* Button scale */
  --btn-h-sm:  44px;  --btn-px-sm: 20px; --btn-fs-sm: 15px;
  --btn-h:     52px;  --btn-px:    28px; --btn-fs:    17px;
  --btn-h-lg:  64px;  --btn-px-lg: 36px; --btn-fs-lg: 19px;
  --btn-radius: var(--radius-pill);

  /* Form scale */
  --input-h-sm:    40px;
  --input-h:       48px;
  --input-h-lg:    56px;
  --input-fs:      16px;
  --input-px:      16px;
  --input-radius:  12px;
  --check-size:    20px;
  --radio-size:    20px;
  --toggle-w:      44px;
  --toggle-h:      24px;
  --toggle-pad:    3px;
}

/* ─── APP — internal admin, PLM, OMS, vendor portal, internal mobile ─── */
[data-surface="app"] {
  /* Type — Linear/Notion grade · Be Vietnam Pro pairing (no Montserrat in admin chrome) */
  --type-display:  700 28px/1.15 var(--font-brand);    /* page title — rare, breadcrumbs preferred */
  --type-h1:       700 22px/1.2  var(--font-brand);    /* section title */
  --type-h2:       700 18px/1.25 var(--font-brand);    /* sub-section */
  --type-h3:       600 15px/1.3  var(--font-brand);    /* card title */
  --type-h4:       600 13px/1.3  var(--font-brand);    /* small card / list group */

  --type-body-lg:  400 15px/1.55 var(--font-body);     /* lede · long-form readme */
  --type-body:     400 13.5px/1.5 var(--font-body);    /* default body */
  --type-body-sm:  400 12.5px/1.45 var(--font-body);   /* secondary text */

  --type-label:    500 12px/1.3  var(--font-body);     /* form label · table header */
  --type-label-sm: 600 10.5px/1  var(--font-body);     /* tiny pill / chip label */
  --type-caption:  400 11.5px/1.4 var(--font-body);    /* metadata, timestamps */

  --type-eyebrow:  700 10.5px/1  var(--font-mono);     /* uppercase mono eyebrow */
  --type-mono:     500 12.5px/1.45 var(--font-mono);   /* inline code, IDs */
  --type-mono-sm:  500 11px/1.4  var(--font-mono);     /* tiny code */
  --type-tag:      600 10.5px/1  var(--font-mono);     /* status pill */

  /* Tabular KPI numerals — Be Vietnam Pro 700 with tnum (NOT Montserrat) */
  --type-num-lg:   700 28px/1.05 var(--font-brand);    /* hero KPI on dashboard */
  --type-num:      600 17px/1.1  var(--font-brand);    /* table number, value */
  --type-num-sm:   600 13.5px/1.2 var(--font-brand);   /* small KPI · table cell */

  /* Form scale — dense, table-aligned (matches button h) */
  --input-h-sm:    28px;
  --input-h:       32px;
  --input-h-lg:    40px;
  --input-fs:      13.5px;
  --input-px:      10px;
  --input-radius:  6px;
  --check-size:    14px;
  --radio-size:    14px;
  --toggle-w:      28px;
  --toggle-h:      16px;
  --toggle-pad:    2px;

  /* Layout */
  --gutter-tight:  8px;
  --gutter:        12px;
  --gutter-wide:   20px;
  --section-pad:   20px 24px;
  --container-max: 100%;            /* fluid — app fills its frame */

  /* Density tiers (app-specific) */
  --row-compact:   32px;
  --row-cozy:      44px;
  --row-spacious:  56px;

  /* Discipline */
  --motion-budget: instant;         /* state transitions only · no scroll reveal */
  --accent-freq:   signal;          /* color = status only */
  --shadow-rest:   var(--shadow-sm);

  /* Button scale — tight for high-density tables */
  --btn-h-sm:  28px;  --btn-px-sm: 10px; --btn-fs-sm: 12px;
  --btn-h:     32px;  --btn-px:    14px; --btn-fs:    13.5px;
  --btn-h-lg:  40px;  --btn-px-lg: 20px; --btn-fs-lg: 15px;
  --btn-radius: var(--radius-sm);  /* squarer corners in dense UI */
}

/* ─── STORE — POS / signage / fitting-room tablet (v3.1) ─── */
[data-surface="store"] {
  /* Type — readable from 2-3m, high-contrast */
  --type-signage:  800 clamp(96px, 12vw, 160px)/0.92 var(--font-impact);   /* window display */
  --type-price:    700 clamp(32px, 4vw,   48px)/1.05  var(--font-numeric);  /* sticker */
  --type-cta:      700 19px/1.2  var(--font-brand);
  --type-body:     500 17px/1.45 var(--font-body);
  --type-body-sm:  500 15px/1.4  var(--font-body);
  --type-label:    600 13px/1.3  var(--font-body);

  /* Layout & tap targets (touch-first) */
  --gutter:                  24px;
  --tap-min:                 56px;
  --tap-min-store-primary:   72px;
  --row-touch:               72px;
  --section-pad:             32px 24px;

  /* Discipline */
  --motion-budget: ambient-loop;    /* signage only · ZERO motion on POS */
  --accent-freq:   high-contrast;   /* navy + gold only · max contrast */
  --shadow-rest:   none;            /* flat · glare-resistant */

  /* Button scale — touch-first, large hit areas */
  --btn-h-sm:  56px;  --btn-px-sm: 24px; --btn-fs-sm: 17px;
  --btn-h:     72px;  --btn-px:    32px; --btn-fs:    19px;
  --btn-h-lg:  88px;  --btn-px-lg: 40px; --btn-fs-lg: 22px;
  --btn-radius: var(--radius);

  /* Form scale — touch-first */
  --input-h-sm:    52px;
  --input-h:       64px;
  --input-h-lg:    80px;
  --input-fs:      17px;
  --input-px:      18px;
  --input-radius:  12px;
  --check-size:    24px;
  --radio-size:    24px;
  --toggle-w:      56px;
  --toggle-h:      32px;
  --toggle-pad:    4px;
}

* { box-sizing: border-box; }

html, body {
  font-family: var(--font-body); font-size: 19px; line-height: 1.7;
  color: var(--fg-1); background: var(--bg);
  -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale;
  text-rendering: optimizeLegibility;
}

h1, .h1 { font: var(--type-h1); letter-spacing: -0.022em; color: var(--fg-1); }
h2, .h2 { font: var(--type-h2); letter-spacing: -0.018em; color: var(--fg-1); }
h3, .h3 { font: var(--type-h3); letter-spacing: -0.01em; color: var(--fg-1); }
p       { font: var(--type-body); color: var(--fg-2); }

.display       { font: var(--type-display); letter-spacing: -0.025em; }
.hero-display  { font: var(--type-hero); letter-spacing: -0.03em; }
.brand-face    { font-family: var(--font-brand); }
.kpi-num       { font: var(--type-kpi); font-variant-numeric: tabular-nums; letter-spacing: -0.025em; }

/* Hero-only artistic italic — Playfair */
.art-italic    { font: var(--type-art-italic); letter-spacing: -0.005em; }

/* Geometric italic accent — Montserrat italic — for H1/H2 inside headlines */
em.accent, .em-accent { font: italic 800 1em/1 var(--font-impact); font-style: italic; color: var(--iris); letter-spacing: -0.015em; }
em.accent.gold,  .em-accent.gold  { color: var(--gold-deep); }
em.accent.mint,  .em-accent.mint  { color: var(--mint-deep); }
em.accent.rose,  .em-accent.rose  { color: var(--rose-deep); }
em.accent.brand, .em-accent.brand { color: var(--brand); }

/* Roman numerals (I/II/III/IV/V) — Montserrat italic 800, per-tone */
.roman        { font: var(--type-roman); }
.roman.iris   { color: var(--iris); }
.roman.gold   { color: var(--gold-deep); }
.roman.mint   { color: var(--mint-deep); }
.roman.rose   { color: var(--rose-deep); }
.roman.brand  { color: var(--brand); }

/* Big-num — gradient numerals for hero KPIs */
.big-num       { font-family: var(--font-impact); font-weight: 800;
                 line-height: 0.85; letter-spacing: -0.04em;
                 color: transparent; background-clip: text; -webkit-background-clip: text;
                 display: inline-block; }
.big-num.brand { background-image: var(--grad-brand); }
.big-num.iris  { background-image: var(--grad-iris); }
.big-num.gold  { background-image: var(--grad-gold); }
.big-num.mint  { background-image: var(--grad-mint); }
.big-num.rose  { background-image: var(--grad-rose); }

/* Section eyebrow — mono uppercase with flanking dashes */
.s-eyebrow {
  font-family: var(--font-mono); font-weight: 700;
  font-size: 13px; letter-spacing: 0.32em; text-transform: uppercase;
  color: var(--brand);
  display: inline-flex; align-items: center; gap: 14px;
}
.s-eyebrow::before, .s-eyebrow::after {
  content: ''; width: 32px; height: 1px; background: currentColor; opacity: 0.5;
}
.s-eyebrow.gold  { color: var(--gold-deep); }
.s-eyebrow.iris  { color: var(--iris-deep); }
.s-eyebrow.mint  { color: var(--mint-deep); }
.s-eyebrow.rose  { color: var(--rose-deep); }

/* Insight callout — mandatory per section */
.insight {
  margin-top: 56px; padding: 36px 44px;
  background: var(--bg); border: 1px solid var(--border); border-radius: var(--radius-lg);
  box-shadow: var(--shadow-sm);
  position: relative;
}
.insight::before {
  content: ''; position: absolute; left: 0; top: 28px; bottom: 28px;
  width: 3px; background: linear-gradient(180deg, var(--gold), var(--gold-deep));
  border-radius: 0 3px 3px 0;
}
.insight-label {
  font-family: var(--font-mono); font-size: 12px; letter-spacing: 0.3em; text-transform: uppercase;
  color: var(--fg-3); font-weight: 700;
  display: inline-flex; align-items: center; gap: 10px;
  margin-bottom: 16px;
}
.insight-label::before { content: ''; width: 18px; height: 1px; background: currentColor; opacity: 0.5; }
.insight-body { font-size: 22px; line-height: 1.6; color: var(--fg-1); }
.insight-body em { font: italic 700 1em/1.6 var(--font-serif); color: var(--iris); }
.insight-body em.gold { color: var(--gold-deep); }
.insight-body em.mint { color: var(--mint-deep); }

/* Status pills — JetBrains Mono uppercase pill */
.tag {
  display: inline-flex; align-items: center;
  font: var(--type-tag); text-transform: uppercase; letter-spacing: 0.6px;
  padding: 3px 10px; border-radius: var(--radius-pill);
  white-space: nowrap;
}
.tag-lg { font-size: 12px; padding: 5px 12px; letter-spacing: 0.8px; }
.tag-live  { background: var(--live-bg);  color: var(--mint-deep); border: 1px solid rgba(16,185,129,.22); }
.tag-build { background: var(--build-bg); color: var(--iris-deep); border: 1px solid rgba(124,108,245,.22); }
.tag-gap   { background: var(--gap-bg);   color: var(--gap);       border: 1px solid rgba(239,68,68,.20); }
.tag-plan  { background: var(--plan-bg);  color: var(--gold-deep); border: 1px solid rgba(245,158,11,.22); }

/* CTA system */
.cta {
  display: inline-flex; align-items: center; gap: 10px;
  padding: 0 32px; height: 56px; border-radius: var(--radius-pill);
  font: 600 17px/1 var(--font-body); text-decoration: none; cursor: pointer; border: none;
  transition: all var(--dur) var(--ease-out);
}
.cta-primary   { background: var(--brand); color: #fff; }
.cta-primary:hover { background: var(--brand-light); transform: translateY(-1px); box-shadow: var(--shadow-brand); }
.cta-secondary { border: 1px solid var(--border); color: var(--fg-1); background: transparent; }
.cta-secondary:hover { background: var(--bg-muted); }
.cta-gold      { background: var(--gold); color: #0e0f24; font-weight: 700; }
.cta-gold:hover { transform: translateY(-1px); box-shadow: var(--shadow-gold); }

/* Utility */
.label   { font: var(--type-label); color: var(--fg-3); }
.caption { font: var(--type-caption); color: var(--fg-3); }
.mono    { font: var(--type-mono); }
.eyebrow { font: var(--type-eyebrow); text-transform: uppercase; letter-spacing: 0.32em; color: var(--brand); }

/* ════════════════════════════════════════════════════════════════════
   QuantyFin Design System · globals.css
   Canonical theme entry — shadcn/ui shape, Tailwind v4 (CSS-first).
   ────────────────────────────────────────────────────────────────────
   Load order:
     1. colors_and_type.css   ← raw QuantyFin values (--brand, --iris, --fg-1,
                                 --border, fonts, shadows, surface adapters)
     2. THIS FILE              ← shadcn semantic roles + @theme + base layer
     3. component layer        ← @apply components (see tailwind/quantyfin.tailwind.css)

   Token model = shadcn "background / foreground" pairs, but the role tokens
   are ALIASES onto the QuantyFin palette (single source of truth stays in
   colors_and_type.css). quantyFin-named utilities (bg-brand, text-fg-2…) keep
   working alongside the semantic roles (bg-background, text-muted-foreground…).

   BUILD mode (Vite/PostCSS): this file is importable as the theme entry.
   NO-BUILD CDN: the browser build only compiles inline <style type="text/
   tailwindcss">, so the deployed mirror of this theme is inlined via
   tailwind/quantyfin.components.css. Keep the two in sync.
   ════════════════════════════════════════════════════════════════════ */

@import "tailwindcss";

@custom-variant dark (&:is(.dark *));

/* ─── Role layer · LIGHT (default) — shadcn semantic tokens → QuantyFin palette ─── */
:root {
  --radius: 14px;                        /* = QuantyFin --radius-md (px, root-size-independent) */

  --background: var(--bg);               /* #fcfcff paper */
  --foreground: var(--fg-1);
  --card: var(--bg);
  --card-foreground: var(--fg-1);
  --popover: var(--bg);
  --popover-foreground: var(--fg-1);

  --primary: var(--brand);               /* QuantyFin navy */
  --primary-foreground: #ffffff;
  --secondary: var(--bg-2);
  --secondary-foreground: var(--fg-1);
  --muted: var(--bg-muted);
  --muted-foreground: var(--fg-3);
  --accent: var(--iris);                 /* AI/tech accent */
  --accent-foreground: #ffffff;
  --destructive: var(--gap);
  --destructive-foreground: #ffffff;

  /* --border lives in colors_and_type.css (QuantyFin border color) — reused as-is */
  --input: var(--border);
  --ring: var(--iris);

  /* Chart palette → QuantyFin accents */
  --chart-1: var(--iris);
  --chart-2: var(--mint);
  --chart-3: var(--brand);
  --chart-4: var(--gold);
  --chart-5: var(--rose);

  /* Sidebar surface → QuantyFin surfaces */
  --sidebar: var(--bg-2);
  --sidebar-foreground: var(--fg-1);
  --sidebar-primary: var(--brand);
  --sidebar-primary-foreground: #ffffff;
  --sidebar-accent: var(--bg-muted);
  --sidebar-accent-foreground: var(--fg-1);
  --sidebar-border: var(--border);
  --sidebar-ring: var(--iris);
}

/* ─── Role layer · DARK (opt-in via .dark) — derived from QuantyFin ink surface ─── */
.dark {
  --background: #0e0f24;                 /* QuantyFin --bg-ink */
  --foreground: #f4f5fb;
  --card: #16183a;
  --card-foreground: #f4f5fb;
  --popover: #16183a;
  --popover-foreground: #f4f5fb;

  --primary: var(--brand-light);         /* lift navy for contrast on dark */
  --primary-foreground: #0e0f24;
  --secondary: #1d2046;
  --secondary-foreground: #f4f5fb;
  --muted: #1d2046;
  --muted-foreground: #9aa0c4;
  --accent: var(--iris);
  --accent-foreground: #ffffff;
  --destructive: #f87171;
  --destructive-foreground: #0e0f24;

  --border: rgba(255, 255, 255, 0.10);
  --input: rgba(255, 255, 255, 0.14);
  --ring: var(--iris);

  --chart-1: var(--iris);
  --chart-2: var(--mint);
  --chart-3: var(--brand-light);
  --chart-4: var(--gold);
  --chart-5: var(--rose);

  --sidebar: #16183a;
  --sidebar-foreground: #f4f5fb;
  --sidebar-primary: var(--brand-light);
  --sidebar-primary-foreground: #0e0f24;
  --sidebar-accent: #1d2046;
  --sidebar-accent-foreground: #f4f5fb;
  --sidebar-border: rgba(255, 255, 255, 0.10);
  --sidebar-ring: var(--iris);
}

/* ─── Theme mapping · roles → Tailwind utilities ─── */
@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);

  /* QuantyFin brand palette kept available alongside roles */
  --color-brand: var(--brand);
  --color-brand-light: var(--brand-light);
  --color-brand-deep: var(--brand-deep);
  --color-brand-tint: var(--brand-tint);
  --color-iris: var(--iris);  --color-iris-deep: var(--iris-deep);  --color-iris-tint: var(--iris-tint);
  --color-gold: var(--gold);  --color-gold-deep: var(--gold-deep);  --color-gold-tint: var(--gold-tint);
  --color-mint: var(--mint);  --color-mint-deep: var(--mint-deep);  --color-mint-tint: var(--mint-tint);
  --color-rose: var(--rose);  --color-rose-deep: var(--rose-deep);  --color-rose-tint: var(--rose-tint);
  --color-gap: var(--gap);
  --color-live: var(--live);  --color-build: var(--build);  --color-plan: var(--plan);
  --color-fg: var(--fg-1);  --color-fg-2: var(--fg-2);  --color-fg-3: var(--fg-3);  --color-fg-on-brand: var(--fg-on-brand);
  --color-paper: var(--bg);  --color-mist: var(--bg-2);  --color-lavender: var(--bg-muted);  --color-ink: var(--bg-ink);  --color-warm: var(--bg-warm);
  --color-line: var(--border);  --color-line-light: var(--border-light);  --color-line-hover: var(--border-hover);

  /* Fonts */
  --font-sans: var(--font-body);  --font-brand: var(--font-brand);  --font-display: var(--font-impact);  --font-serif: var(--font-serif);  --font-mono: var(--font-mono);

  /* Radius — QuantyFin keeps explicit sm/md/lg/xl; 2xl+ derived from --radius (shadcn) */
  --radius-xs: var(--radius-xs);
  --radius-sm: var(--radius-sm);
  --radius-md: var(--radius-md);
  --radius-lg: var(--radius-lg);
  --radius-xl: var(--radius-xl);
  --radius-2xl: calc(var(--radius) * 1.8);
  --radius-3xl: calc(var(--radius) * 2.2);
  --radius-4xl: calc(var(--radius) * 2.6);

  /* Shadows (iris-tinted) */
  --shadow-sm: var(--shadow-sm);  --shadow-md: var(--shadow-md);  --shadow-lg: var(--shadow-lg);  --shadow-xl: var(--shadow-xl);  --shadow-brand: var(--shadow-brand);  --shadow-gold: var(--shadow-gold);

  /* Type scale (tokenized — use text-h1 / text-body / text-eyebrow, not arbitrary text-[Npx]) */
  --text-eyebrow: 13px;    --text-eyebrow--line-height: 1;
  --text-caption: 13px;    --text-caption--line-height: 1.5;
  --text-label: 14px;      --text-label--line-height: 1.4;
  --text-body-sm: 16px;    --text-body-sm--line-height: 1.6;
  --text-body: 19px;       --text-body--line-height: 1.7;
  --text-body-lg: 23px;    --text-body-lg--line-height: 1.65;
  --text-card-title: 17px; --text-card-title--line-height: 1.3;
  --text-h3: 26px;         --text-h3--line-height: 1.3;
  --text-h2: 32px;         --text-h2--line-height: 1.18;
  --text-h1: 56px;         --text-h1--line-height: 1.08;
  --text-display: 88px;    --text-display--line-height: 0.98;
  --text-hero: 104px;      --text-hero--line-height: 0.94;
}

/* ─── Base layer (shadcn convention) ─── */
@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
  }
}
